class XmlConfigurationParser(
  maxEntityExpansions: Int = 0,
  allowDTD: Boolean = false,
  maxElementDepth: Int = 100
) {

  def parseConfiguration(xmlString: String): Try[ParsedConfiguration] = {
    Try {
      val factory = SAXParserFactory.newInstance()
      factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
      factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
      factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", !allowDTD)
      factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
      factory.setFeature("http://xml.org/sax/features/validation", false)
      factory.setXIncludeAware(false)
      factory.setNamespaceAware(true)
      
      if (maxEntityExpansions == 0) {
        factory.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true)
      }

      val parser = factory.newSAXParser()
      val xmlReader = parser.getXMLReader
      
      val adapter = new scala.xml.parsing.NoBindingFactoryAdapter
      xmlReader.setContentHandler(adapter)
      
      val source = new InputSource(new StringReader(xmlString))
      xmlReader.parse(source)
      
      val elem = adapter.rootElem
      
      validateDepth(elem, 0)
      extractConfiguration(elem)
    }
  }

  private def validateDepth(node: Node, currentDepth: Int): Unit = {
    if (currentDepth > maxElementDepth) {
      throw new IllegalArgumentException(s"XML depth exceeds maximum allowed depth of $maxElementDepth")
    }
    node.child.foreach {
      case e: Elem => validateDepth(e, currentDepth + 1)
      case _ => 
    }
  }

  private def extractConfiguration(root: Elem): ParsedConfiguration = {
    val namespace = (root \ "@namespace").headOption.map(_.text)
    val version = (root \ "@version").headOption.map(_.text)
    
    val settings = (root \ "setting").flatMap { settingNode =>
      val key = (settingNode \ "@key").text
      val value = (settingNode \ "@value").headOption.map(_.text)
        .orElse((settingNode \ "value").headOption.map(_.text))
        .getOrElse(settingNode.text.trim)
      
      val metadata = settingNode.attributes.asAttrMap
        .filterKeys(k => k != "key" && k != "value")
      
      if (key.nonEmpty) {
        Some(key -> ConfigurationSetting(key, value, metadata))
