class ConfigurationService(parser: XmlConfigurationParser) {
  
  def processConfigurationRequest(xmlContent: String): Try[ParsedConfiguration] = {
    if (xmlContent == null || xmlContent.trim.isEmpty) {
      Failure(new IllegalArgumentException("XML content cannot be empty"))
    } else if (xmlContent.length > 1024 * 1024) {
      Failure(new IllegalArgumentException("XML content exceeds maximum size of 1MB"))
    } else {
      parser.parseConfiguration(xmlContent)
    }
  }
  
  def extractSetting(config: ParsedConfiguration, key: String): Option[String] = {
    config.settings.get(key).map(_.value)
  }
  
  def extractAllSettings(config: ParsedConfiguration): Map[String, String] = {
    config.settings.map { case (k, v) => k -> v.value }
  }
  
  def mergeConfigurations(configs: Seq[ParsedConfiguration]): ParsedConfiguration = {
    val mergedSettings = configs.foldLeft(Map.empty[String, ConfigurationSetting]) {
      case (acc, config) => acc ++ config.settings
    }
    
    val namespace = configs.flatMap(_.namespace).headOption
    val version = configs.flatMap(_.version).lastOption
    
    ParsedConfiguration(mergedSettings, namespace, version)
  }
  
  def validateConfiguration(config: ParsedConfiguration, requiredKeys: Set[String]): Either[List[String], ParsedConfiguration] = {
    val missingKeys = requiredKeys.filterNot(config.settings.contains)
    
    if (missingKeys.isEmpty) {
      Right(config)
    } else {
      Left(missingKeys.toList)
    }
  }
}

