trait ConfigurationApi {
  val configService: ConfigurationService
  
  def handleConfigurationUpload(xmlContent: String): ApiResponse = {
    configService.processConfigurationRequest(xmlContent) match {
      case Success(config) =>
        ApiResponse(
          success = true,
          data = Some(config),
          message = s"Successfully parsed ${config.settings.size} settings"
        )
      case Failure(exception) =>
        ApiResponse(
          success = false,
          data = None,
          message = s"Failed to parse configuration: ${exception.getMessage}",
          error = Some(exception.getClass.getSimpleName)
        )
    }
  }
  
  def handleSettingRetrieval(xmlContent: String, key: String): ApiResponse = {
    configService.processConfigurationRequest(xmlContent) match {
      case Success(config) =>
        configService.extractSetting(config, key) match {
          case Some(value) =>
            ApiResponse(
              success = true,
              data = Some(Map("key" -> key, "value" -> value)),
              message = s"Setting '$key' retrieved successfully"
            )
          case None =>
            ApiResponse(
              success = false,
              data = None,
              message = s"Setting '$key' not found in configuration"
            )
        }
      case Failure(exception) =>
        ApiResponse(
          success = false,
          data = None,
          message = s"Failed to parse configuration: ${exception.getMessage}",
          error = Some(exception.getClass.getSimpleName)
        )
    }
  }
  
  def handleBulkConfigurationUpload(xmlContents: Seq[String]): ApiResponse = {
    val results = xmlContents.map(configService.processConfigurationRequest)
    val failures = results.collect { case Failure(ex) => ex }
    
    if (failures.isEmpty) {
      val configs = results.collect { case Success(config) => config }
      val merged = configService.mergeConfigurations(configs)
      ApiResponse(
        success = true,
        data = Some(merged),
        message = s"Successfully merged ${configs.size} configurations with ${merged.settings.size} total settings"
      )
    } else {
      ApiResponse(
        success = false,
        data = None,
        message = s"Failed to parse ${failures.size} out of ${xmlContents.size} configurations",
        error = Some(failures.map(_.getMessage).mkString("; "))
      )
    }
  }
}

case class ApiResponse(
  success: Boolean,
  data: Option[Any],
  message: String,
  error: Option[String] = None
)

class ConfigurationManagementSystem extends ConfigurationApi {
  override val configService: ConfigurationService = ConfigurationService()
  
  private var configurationStore: Map[String, ParsedConfiguration] = Map.empty
  
  def storeConfiguration(id: String, xmlContent: String): ApiResponse = {
    configService.processConfigurationRequest(xmlContent) match {
      case Success(config) =>
        configurationStore = configurationStore + (id -> config)
        ApiResponse(
          success = true,
          data = Some(Map("id" -> id, "settingsCount" -> config.settings.size)),
          message = s"Configuration stored with ID: $id"
        )
      case Failure(exception) =>
        ApiResponse(
          success = false,
          data = None,
          message = s"Failed to store configuration: ${exception.getMessage}",
          error = Some(exception.getClass.getSimpleName)
        )
    }
  }
  
  def retrieveConfiguration(id: String): Option[ParsedConfiguration] = {
    configurationStore.get(id)
  }
  
  def listConfigurations(): Map[String, Int] = {
    configurationStore.map { case (id, config) => id -> config.settings.size }
  }
  
  def deleteConfiguration(id: String): Boolean = {
    val existed = configurationStore.contains(id)
    configurationStore = configurationStore - id
    existed
  }
}